    {
        _statusStrip = new StatusStrip();
        // .NET 9 breaking change: StatusStrip now uses ToolStripSystemRenderer by
        // default, matching ToolStrip. Set Professional to preserve .NET 8 visuals.
        _statusStrip.RenderMode = ToolStripRenderMode.Professional;
        Controls.Add(_statusStrip);
    }

    public void ShowDropDown(IWindowsFormsEditorService editorService, Control control)
    {
        // .NET 9 breaking change: DropDownControl now throws ArgumentNullException
        // when passed null instead of silently ignoring it.
        if (control is not null)
        {
            editorService.DropDownControl(control);
        }
    }

    // .NET 9 recommended pattern: use LibraryImport (source-generated) instead of
    // DllImport for P/Invoke. Requires AllowUnsafeBlocks in the project file.
    [LibraryImport("user32.dll", EntryPoint = "MessageBoxW", StringMarshalling = StringMarshalling.Utf16)]
    private static partial int NativeMessageBox(nint hWnd, string text, string caption, uint type);

    public void ShowNativeMessage(string message)
    {
        NativeMessageBox(0, message, DisplayName ?? "Info", 0);
    }
}

